  1→/*
  2→ * parity.c - Dual-execution parity testing for OCaml bridge
  3→ *
  4→ * Implements game state snapshot, restore, and field-by-field comparison.
  5→ * Used to detect divergences between OCaml and C execution paths.
  6→ */
  7→
  8→#ifdef USE_OX_BRIDGE
  9→
 10→#include <cstdio>
 11→#include <cstdlib>
 12→#include <cstring>
 13→#include <cstdarg>
 14→
 15→#ifdef BUILD_DESCENT2
 16→#include "main_d2/object.h"
 17→#include "main_d2/ai.h"
 18→#include "main_d2/aistruct.h"
 19→#include "main_d2/player.h"
 20→#include "main_d2/wall.h"
 21→#include "main_d2/segment.h"
 22→#include "main_d2/gameseg.h"
 23→#include "main_shared/game_shared.h"
 24→#include "misc/rand.h"
 25→#else
 26→#include "main_d1/object.h"
 27→#include "main_d1/ai.h"
 28→#include "main_d1/aistruct.h"
 29→#include "main_d1/player.h"
 30→#include "main_d1/wall.h"
 31→#include "main_d1/segment.h"
 32→#include "main_d1/gameseg.h"
 33→#include "main_shared/game_shared.h"
 34→#include "misc/rand.h"
 35→#endif
 36→
 37→#include "ox/parity.h"
 38→
 39→/* Pre-allocated snapshot buffers (~350KB each, ~1MB total) */
 40→game_state_snapshot parity_snap_before;
 41→game_state_snapshot parity_snap_after_ocaml;
 42→game_state_snapshot parity_snap_after_c;
 43→
 44→/* Runtime configuration */
 45→static int parity_initialized = 0;
 46→static int parity_assert_on_diverge = 0;
 47→static FILE *parity_log_file = NULL;
 48→static int parity_total_divergences = 0;
 49→
 50→void parity_init(void)
 51→{
 52→	if (parity_initialized) return;
 53→	parity_initialized = 1;
 54→
 55→	const char *assert_env = getenv("OX_PARITY_ASSERT");
 56→	if (assert_env && atoi(assert_env))
 57→		parity_assert_on_diverge = 1;
 58→
 59→	const char *log_env = getenv("OX_PARITY_LOG");
 60→	if (log_env && log_env[0]) {
 61→		parity_log_file = fopen(log_env, "w");
 62→		if (!parity_log_file)
 63→			fprintf(stderr, "PARITY: failed to open log file '%s'\n", log_env);
 64→	}
 65→
 66→	fprintf(stderr, "PARITY: initialized (assert=%d, log=%s)\n",
 67→		parity_assert_on_diverge,
 68→		log_env ? log_env : "stderr");
 69→}
 70→
 71→/* Helper: write to both stderr and optional log file */
 72→static void parity_log(const char *fmt, ...)
 73→{
 74→	va_list ap;
 75→	va_start(ap, fmt);
 76→	vfprintf(stderr, fmt, ap);
 77→	va_end(ap);
 78→
 79→	if (parity_log_file) {
 80→		va_start(ap, fmt);
 81→		vfprintf(parity_log_file, fmt, ap);
 82→		va_end(ap);
 83→		fflush(parity_log_file);
 84→	}
 85→}
 86→
 87→void parity_snapshot(game_state_snapshot *dst)
 88→{
 89→	int n_objects = Highest_object_index + 1;
 90→	if (n_objects > PARITY_MAX_OBJECTS)
 91→		n_objects = PARITY_MAX_OBJECTS;
 92→	if (n_objects > 0) {
 93→		memcpy(dst->objects, Objects, n_objects * sizeof(object));
 94→		memcpy(dst->ai_local_info, Ai_local_info, n_objects * sizeof(ai_local));
 95→	}
 96→
 97→	memcpy(dst->players, Players, PARITY_MAX_PLAYERS * sizeof(player));
 98→
 99→	int n_walls = Num_walls;
100→	if (n_walls > PARITY_MAX_WALLS)
101→		n_walls = PARITY_MAX_WALLS;
102→	if (n_walls > 0)
103→		memcpy(dst->walls, Walls, n_walls * sizeof(wall));
104→
105→	/* Save per-segment object list heads */
106→	int n_segs = Highest_segment_index + 1;
107→	if (n_segs > PARITY_MAX_SEGMENTS)
108→		n_segs = PARITY_MAX_SEGMENTS;
109→	for (int i = 0; i < n_segs; i++)
110→		dst->seg_objects[i] = Segments[i].objects;
111→	dst->highest_segment_index = Highest_segment_index;
112→
113→	dst->rand_state = P_Rand_get_state();
114→	dst->highest_object_index = Highest_object_index;
115→	dst->player_is_dead = Player_is_dead;
116→	dst->player_exploded = Player_exploded;
117→	dst->overall_agitation = Overall_agitation;
118→	dst->num_walls = Num_walls;
119→	dst->frame_time = FrameTime;
120→	dst->game_time = GameTime;
121→	dst->frame_count = FrameCount;
122→}
123→
124→void parity_restore(const game_state_snapshot *src)
125→{
126→	int n_objects = src->highest_object_index + 1;
127→	if (n_objects > PARITY_MAX_OBJECTS)
128→		n_objects = PARITY_MAX_OBJECTS;
129→	if (n_objects > 0) {
130→		memcpy(Objects, src->objects, n_objects * sizeof(object));
131→		memcpy(Ai_local_info, src->ai_local_info, n_objects * sizeof(ai_local));
132→	}
133→
134→	memcpy(Players, src->players, PARITY_MAX_PLAYERS * sizeof(player));
135→
136→	int n_walls = src->num_walls;
137→	if (n_walls > PARITY_MAX_WALLS)
138→		n_walls = PARITY_MAX_WALLS;
139→	if (n_walls > 0)
140→		memcpy(Walls, src->walls, n_walls * sizeof(wall));
141→
142→	Highest_object_index = src->highest_object_index;
143→	Player_is_dead = src->player_is_dead;
144→	Player_exploded = src->player_exploded;
145→	Overall_agitation = src->overall_agitation;
146→	Num_walls = src->num_walls;
147→	FrameTime = src->frame_time;
148→	GameTime = src->game_time;
149→	FrameCount = src->frame_count;
150→
151→	P_Rand_set_state(src->rand_state);
152→
153→	/* Restore per-segment object list heads */
154→	int n_segs = src->highest_segment_index + 1;
155→	if (n_segs > PARITY_MAX_SEGMENTS)
156→		n_segs = PARITY_MAX_SEGMENTS;
157→	for (int i = 0; i < n_segs; i++)
158→		Segments[i].objects = src->seg_objects[i];
159→}
160→
161→/* ---- Field-by-field comparison ---- */
162→
163→/* Macro to compare a field and log divergence */
164→#define CMP_FIELD(prefix, field, fmt_a, fmt_b) do { \
165→	if ((a_val = (fmt_a)) != (b_val = (fmt_b))) { \
166→		parity_log("  %s." #field ": OCaml=0x%X C=0x%X\n", prefix, a_val, b_val); \
167→		divergences++; \
168→	} \
169→} while(0)
170→
171→static int compare_object(const object *oa, const object *ob, int idx, const char *fn_name, int frame)
172→{
173→	int divergences = 0;
174→	int a_val, b_val;
175→	char prefix[64];
176→	snprintf(prefix, sizeof(prefix), "Objects[%d]", idx);
177→
178→	/* Skip OBJ_NONE objects */
179→	if (oa->type == 255 && ob->type == 255) /* OBJ_NONE */
180→		return 0;
181→
182→	/* Core fields */
183→	CMP_FIELD(prefix, type, oa->type, ob->type);
184→	CMP_FIELD(prefix, id, oa->id, ob->id);
185→	CMP_FIELD(prefix, control_type, oa->control_type, ob->control_type);
186→	CMP_FIELD(prefix, movement_type, oa->movement_type, ob->movement_type);
187→	CMP_FIELD(prefix, flags, oa->flags, ob->flags);
188→	CMP_FIELD(prefix, segnum, oa->segnum, ob->segnum);
189→
190→	/* Position */
191→	CMP_FIELD(prefix, pos.x, oa->pos.x, ob->pos.x);
192→	CMP_FIELD(prefix, pos.y, oa->pos.y, ob->pos.y);
193→	CMP_FIELD(prefix, pos.z, oa->pos.z, ob->pos.z);
194→
195→	/* Orientation */
196→	CMP_FIELD(prefix, orient.rvec.x, oa->orient.rvec.x, ob->orient.rvec.x);
197→	CMP_FIELD(prefix, orient.rvec.y, oa->orient.rvec.y, ob->orient.rvec.y);
198→	CMP_FIELD(prefix, orient.rvec.z, oa->orient.rvec.z, ob->orient.rvec.z);
199→	CMP_FIELD(prefix, orient.uvec.x, oa->orient.uvec.x, ob->orient.uvec.x);
200→	CMP_FIELD(prefix, orient.uvec.y, oa->orient.uvec.y, ob->orient.uvec.y);
201→	CMP_FIELD(prefix, orient.uvec.z, oa->orient.uvec.z, ob->orient.uvec.z);
202→	CMP_FIELD(prefix, orient.fvec.x, oa->orient.fvec.x, ob->orient.fvec.x);
203→	CMP_FIELD(prefix, orient.fvec.y, oa->orient.fvec.y, ob->orient.fvec.y);
204→	CMP_FIELD(prefix, orient.fvec.z, oa->orient.fvec.z, ob->orient.fvec.z);
205→
206→	/* Size, shields, lifeleft */
207→	CMP_FIELD(prefix, size, oa->size, ob->size);
208→	CMP_FIELD(prefix, shields, oa->shields, ob->shields);
209→	CMP_FIELD(prefix, lifeleft, oa->lifeleft, ob->lifeleft);
210→
211→	/* Contains */
212→	CMP_FIELD(prefix, contains_type, oa->contains_type, ob->contains_type);
213→	CMP_FIELD(prefix, contains_id, oa->contains_id, ob->contains_id);
214→	CMP_FIELD(prefix, contains_count, oa->contains_count, ob->contains_count);
215→
216→	/* Physics info (if physics object) */
217→	if (oa->movement_type == 1 || ob->movement_type == 1) { /* MT_PHYSICS */
218→		CMP_FIELD(prefix, phys.velocity.x, oa->mtype.phys_info.velocity.x, ob->mtype.phys_info.velocity.x);
219→		CMP_FIELD(prefix, phys.velocity.y, oa->mtype.phys_info.velocity.y, ob->mtype.phys_info.velocity.y);
220→		CMP_FIELD(prefix, phys.velocity.z, oa->mtype.phys_info.velocity.z, ob->mtype.phys_info.velocity.z);
221→		CMP_FIELD(prefix, phys.thrust.x, oa->mtype.phys_info.thrust.x, ob->mtype.phys_info.thrust.x);
222→		CMP_FIELD(prefix, phys.thrust.y, oa->mtype.phys_info.thrust.y, ob->mtype.phys_info.thrust.y);
223→		CMP_FIELD(prefix, phys.thrust.z, oa->mtype.phys_info.thrust.z, ob->mtype.phys_info.thrust.z);
224→		CMP_FIELD(prefix, phys.mass, oa->mtype.phys_info.mass, ob->mtype.phys_info.mass);
225→		CMP_FIELD(prefix, phys.drag, oa->mtype.phys_info.drag, ob->mtype.phys_info.drag);
226→		CMP_FIELD(prefix, phys.rotvel.x, oa->mtype.phys_info.rotvel.x, ob->mtype.phys_info.rotvel.x);
227→		CMP_FIELD(prefix, phys.rotvel.y, oa->mtype.phys_info.rotvel.y, ob->mtype.phys_info.rotvel.y);
228→		CMP_FIELD(prefix, phys.rotvel.z, oa->mtype.phys_info.rotvel.z, ob->mtype.phys_info.rotvel.z);
229→		CMP_FIELD(prefix, phys.rotthrust.x, oa->mtype.phys_info.rotthrust.x, ob->mtype.phys_info.rotthrust.x);
230→		CMP_FIELD(prefix, phys.rotthrust.y, oa->mtype.phys_info.rotthrust.y, ob->mtype.phys_info.rotthrust.y);
